        # handle multiple ranges separated by commas
        parts = [p.strip() for p in str(span).split(',')]
        for p in parts:
            m = re.split(r'\u2013|\-|–', p)
            if len(m) != 2:
                continue
            end = m[1].strip()
            # treat 'Open 24 hours'
            if '24' in p and 'hour' in p.lower():
                return True
            # parse end time like 6PM, 6:30PM, 18:00
            mt = re.match(r'^(\d{1,2})(?::(\d{2}))?\s*(AM|PM)?$', end, re.I)
            if not mt:
                continue
            hh = int(mt.group(1))
            mm = int(mt.group(2) or 0)
            ap = (mt.group(3) or '').upper()
            if ap == 'PM' and hh != 12:
                hh += 12
            if ap == 'AM' and hh == 12:
                hh = 0
            # if no AM/PM assume 24h
            end_minutes = hh*60+mm
            if end_minutes > 18*60:
                return True
    return False

biz['hours_list'] = biz['hours'].apply(parse_hours)
biz['after_6pm_weekday'] = biz['hours_list'].apply(closes_after_6pm)

merged = biz.merge(ratings, on='gmap_id', how='inner')
merged['avg_rating'] = merged['avg_rating'].astype(float)

result_df = merged[merged['after_6pm_weekday']].sort_values(['avg_rating','review_count'], ascending=[False, False]).head(5)

out = []
for _, r in result_df.iterrows():
    out.append({
        'name': r['name'],
        'hours': r['hours_list'],
        'avg_rating': round(float(r['avg_rating']), 4)
    })

print('__RESULT__:')
print(json.dumps(out))"}

